solution_code:
#include <iostream>
#include <stdexcept>

void throw_by_code(int code) {
    if (code == 1) throw std::out_of_range("range");
    if (code == 2) throw std::runtime_error("rt");
    if (code == 3) throw 99;
}

int main() {
    int code;
    std::cin >> code;

    try {
        throw_by_code(code);
        std::cout << "no exception\n";
    } catch (const std::out_of_range& e) {
        std::cout << "out_of_range: " << e.what() << "\n";
    } catch (const std::runtime_error& e) {
        std::cout << "runtime_error: " << e.what() << "\n";
    } catch (...) {
        std::cout << "unknown exception\n";
    }

    return 0;
}

