solution_code:
#include <iostream>
#include <stdexcept>
#include <string>

std::string safe_lookup(int key) {
    if (key == 1) return "alpha";
    if (key == 2) return "beta";
    if (key == 3) return "gamma";
    throw std::out_of_range("key not found");
}

int main() {
    int key;
    std::cin >> key;

    try {
        std::string val = safe_lookup(key);
        std::cout << "Value: " << val << "\n";
    } catch (const std::out_of_range&) {
        std::cout << "Not found: " << key << "\n";
    } catch (...) {
        std::cout << "Unexpected error\n";
    }

    return 0;
}
